import React, { use } from "react";
import { Link } from "react-router-dom";
import axios from "axios";

function ViewProduct()
{
    const [loading, setLoading] = useState(true);
    const [viewProduct, setViewProduct] = useState([]);

    useEffect(() =>
    {
        axios.get(`/api/view-product`).then(res =>
        {
            if (res.data.status === 200)
            {
                setViewProduct(res.data.products);
                setLoading(false);
            }
            else if (res.data.status === 404)
            {
                alert(res.data.message);
            }
        });
    }, []);

    if (loading)
    {
        return <h4>Loading Product...</h4>;
    }
    else
    {
        viewProduct.map((item) =>
        {
            return (
                <tr key={item.id}>
                    <td>{item.category_id}</td>
                    <td>{item.name}</td>
                    <td>{item.selling_price}</td>
                    <td>{item.image}</td>
                    <td>
                        <Link to={`/admin/edit-product/${item.id}`} className="btn btn-success btn-sm">Edit</Link>
                    </td>
                    <td>
                        <button type="button" className="btn btn-danger btn-sm">Delete</button>
                    </td>
                </tr>
            );
        });
    }

    return (
        <div className="container mt-4">
            <div className="card-header">
                <h4>View Products
                    <Link to={'/admin/add-product'} className="btn btn-primary btn-sm float-end">Add Product</Link>
                </h4>
            </div>
            <div className="card-body">
                <div className="table-responsive">
                    <table className="table table-bordered table-striped">
                        <thead>
                            <tr>
                                <th>ID</th>
                                <th>Category Name</th>
                                <th>Product Name</th>
                                <th>Selling Price</th>
                                <th>Image</th>
                                <th>Edit</th>
                                <th>Delete</th>
                            </tr>
                        </thead>
                        <tbody>
                        </tbody>

                    </table>
                </div>
            </div>
        </div>
    );
}

export default ViewProduct;
